// Normaliza input e monta query_key
function stripAccents(s){ return String(s||'').normalize('NFD').replace(/[\u0300-\u036f]/g,''); }
function norm(s){ return stripAccents(String(s||'').trim()).toUpperCase().replace(/\s+/g,' '); }

const body = ($json && $json.body) ? $json.body : ($json || {});
const scope = (body.scope === 'endereco') ? 'endereco' : 'municipio';
const uf  = norm(body.uf).slice(0,2);
const mun = norm(body.municipio);
const end = norm(body.endereco);
const cep = String(body.cep || '').replace(/\D/g,'').slice(0,8);

let key, query;
if (scope === 'endereco'){
  if (!end && !cep) return [{ json: { ok:false, error:'endereco ou cep obrigatorio para scope=endereco' } }];
  key = [cep || 'NOCEP', end || 'NOEND', mun || 'NOMUN', uf || 'NOUF'].join('|');
  // Nominatim aceita CEP brasileiro direto (postalcode) ou query livre.
  if (cep && end){
    query = end + ', ' + (mun ? mun + ', ' : '') + (uf ? uf + ', ' : '') + cep + ', Brasil';
  } else if (cep){
    query = cep + ', Brasil';
  } else {
    query = end + (mun ? ', ' + mun : '') + (uf ? ', ' + uf : '') + ', Brasil';
  }
} else {
  if (!mun || !uf) return [{ json: { ok:false, error:'uf e municipio obrigatorios para scope=municipio' } }];
  key = mun + '|' + uf;
  query = mun + ', ' + uf + ', Brasil';
}
return [{ json: { ok:true, scope, query_key:key, query, uf, municipio:mun, endereco:end, cep } }];

const ctx = $('Normalize').first().json;
const row = ($input.first() && $input.first().json && $input.first().json.row) || null;
const hasHit = row && (row.lat != null || row.ok === false);
// Se já consultamos antes (mesmo que tenha falhado), retornamos do cache para evitar martelar Nominatim.
return [{ json: Object.assign({}, ctx, { cache_hit: !!hasHit, cache_row: row }) }];

const ctx = $('Carry cache').first().json;
const items = $input.all();
let hit = null;
for (const it of items){
  const j = it && it.json;
  if (Array.isArray(j) && j.length){ hit = j[0]; break; }
  if (j && j.lat != null && j.lon != null){ hit = j; break; }
}
const lat = hit ? Number(hit.lat) : null;
const lng = hit ? Number(hit.lon) : null;
const display = hit ? String(hit.display_name || '') : null;
const okFlag = Number.isFinite(lat) && Number.isFinite(lng);
return [{ json: Object.assign({}, ctx, { lat: okFlag ? lat : null, lng: okFlag ? lng : null, display, geocode_ok: okFlag }) }];

function stripAccents(s){ return String(s||'').normalize('NFD').replace(/[\u0300-\u036f]/g,''); }
function norm(s){ return stripAccents(String(s||'').trim()).toUpperCase().replace(/\s+/g,' '); }

const body = ($json && $json.body) ? $json.body : ($json || {});
const scope = (body.scope === 'endereco') ? 'endereco' : 'municipio';
const items = Array.isArray(body.items) ? body.items : [];
const hardCap = 200; // proteção contra abuso (200 lookups ~ 220s)
if (items.length === 0) return [{ json: { ok:false, error:'items vazio' } }];
if (items.length > hardCap) return [{ json: { ok:false, error:'máximo ' + hardCap + ' itens por chamada' } }];

const out = [];
for (const it of items){
  const uf  = norm(it.uf).slice(0,2);
  const mun = norm(it.municipio);
  const end = norm(it.endereco);
  const cep = String(it.cep || '').replace(/\D/g,'').slice(0,8);
  let key, query;
  if (scope === 'endereco'){
    if (!end && !cep) continue;
    key = [cep || 'NOCEP', end || 'NOEND', mun || 'NOMUN', uf || 'NOUF'].join('|');
    query = (end ? end : '') + (mun ? ', ' + mun : '') + (uf ? ', ' + uf : '') + (cep ? ', ' + cep : '') + ', Brasil';
  } else {
    if (!mun || !uf) continue;
    key = mun + '|' + uf;
    query = mun + ', ' + uf + ', Brasil';
  }
  out.push({ json: { scope, query_key: key, query, uf, municipio: mun, endereco: end, cep } });
}
if (out.length === 0) return [{ json: { ok:false, error:'nenhum item válido após normalização' } }];
return out;

// Marca cada item como cached ou miss. Itens preservam o input + cache_row.
const out = [];
for (const it of $input.all()){
  const ctx = it.json || {};
  const row = ctx.row || null;
  const hasHit = row && (row.lat != null || row.ok === false);
  out.push({ json: Object.assign({}, ctx, { cache_hit: !!hasHit, cache_row: row }) });
}
return out;

// Para os MISSES, percorre sequencialmente respeitando rate-limit (1.1s) do Nominatim.
const items = $input.all();
const results = [];
async function sleep(ms){ return new Promise(r => setTimeout(r, ms)); }
for (let i = 0; i < items.length; i++){
  const it = items[i].json || {};
  if (i > 0) await sleep(1100); // respeita 1 req/s
  let lat = null, lng = null, display = null, okFlag = false;
  try {
    const url = 'https://nominatim.openstreetmap.org/search?format=json&limit=1&countrycodes=br&accept-language=pt-BR&q=' + encodeURIComponent(it.query);
    const r = await this.helpers.httpRequest({
      method: 'GET',
      url,
      headers: { 'User-Agent': 'castor-agent/1.0 (geocode cache; contact admin@castor.com.br)' },
      json: true,
      timeout: 15000
    });
    const hit = Array.isArray(r) && r.length ? r[0] : null;
    if (hit){
      lat = Number(hit.lat); lng = Number(hit.lon);
      display = String(hit.display_name || '');
      okFlag = Number.isFinite(lat) && Number.isFinite(lng);
    }
  } catch (e) {
    // mantém okFlag=false; persistimos a falha pra não retentar
  }
  results.push({ json: Object.assign({}, it, { lat: okFlag ? lat : null, lng: okFlag ? lng : null, display, geocode_ok: okFlag }) });
}
return results;

// Junta hits do cache + lookups Nominatim em uma lista final.
const hits = $('Hit?').all().filter(it => (it.json||{}).cache_hit).map(it => {
  const j = it.json || {};
  const row = j.cache_row || {};
  return { query_key: j.query_key, scope: j.scope, lat: row.lat, lng: row.lng, display_name: row.display_name, cached: true, source: row.source || 'nominatim' };
});
const fresh = $('Nominatim batch').all().map(it => {
  const j = it.json || {};
  return { query_key: j.query_key, scope: j.scope, lat: j.lat, lng: j.lng, display_name: j.display, cached: false, source: 'nominatim' };
});
const items = hits.concat(fresh);
return [{ json: { ok: true, data: { count: items.length, items }, error: null } }];
